const b = $json.body || $json;
const c = b.criteria || {};

// criteria.locCodes (array of atHome loc codes, e.g. ["L10-belair","L10-merl"])
// is the canonical shape since BBInvest S2 (zones model).
// Multiple codes are joined by comma -> atHome accepts loc=L10-a,L10-b natively.
// Backward compat: criteria.loc (string), and criteria.communes[0] (legacy Sprint 1).
function pickLoc() {
  if (Array.isArray(c.locCodes) && c.locCodes.length) {
    return c.locCodes
      .map(s => String(s).trim())
      .filter(Boolean)
      .join(',');
  }
  if (c.loc) return c.loc;
  const first = (c.communes && c.communes[0]) || '';
  if (/^l\d+-/i.test(first)) return first.replace(/^l/i, 'L');
  return null;
}
const loc = pickLoc();

const APT_PTYPES = 'flat,4,7,5,6,42,32,41,43';
const HOUSE_PTYPES = 'house';

const pairs = [];
const add = (k, v) => { if (v !== undefined && v !== null && v !== '') pairs.push(k + '=' + String(v)); };
add('tr', 'buy');
add('ptypes', c.propertyType === 'house' ? HOUSE_PTYPES : APT_PTYPES);
add('srf_min', c.surfaceMin);
add('srf_max', c.surfaceMax);
add('price_min', c.priceMin);
add('price_max', c.priceMax);
add('bedrooms_min', c.bedroomsMin);
add('old_build', 'true');
if (loc) add('loc', loc);
add('page', c.page || '1');
const url = 'https://www.athome.lu/srp/?' + pairs.join('&');
return [{ json: { runId: b.runId, ingestUrl: b.ingestUrl, ingestSecret: b.ingestSecret, criteria: c, searchUrl: url } }];

const ctx = $('Construit URL SRP').first().json;
const c = ctx.criteria || {};
const html = $json.data || $json.body || '';

function extractState(html) {
  const mi = html.indexOf('window.__INITIAL_STATE__');
  if (mi === -1) throw new Error('INITIAL_STATE introuvable (page bloquee ou structure changee)');
  let i = html.indexOf('=', mi) + 1;
  while (/\s/.test(html[i])) i++;
  const s = i; let depth = 0, inStr = false, esc = false;
  for (; i < html.length; i++) {
    const ch = html[i];
    if (esc) { esc = false; continue; }
    if (ch === '\\') { esc = true; continue; }
    if (ch === '"') { inStr = !inStr; continue; }
    if (inStr) continue;
    if (ch === '{') depth++;
    else if (ch === '}') { depth--; if (depth === 0) { i++; break; } }
  }
  return JSON.parse(html.slice(s, i).replace(/:\s*undefined/g, ': null'));
}

const state = extractState(html);
const list = (state.search && state.search.list) || [];
const listings = (state.search && state.search.listings) || [];
const total = (state.search && state.search.total) || list.length;
const permById = {};
for (const x of listings) permById[x.id] = x.permalink && x.permalink.fr;

const kw = (c.keywords || []).map(k => k.toLowerCase());

let countSold = 0, countNew = 0, countNoKw = 0;
const out = [];
for (const a of list) {
  if (a.isSoldProperty) { countSold++; continue; }
  if (a.isNewBuild) { countNew++; continue; }
  const desc = (a.description || '').toLowerCase();
  if (kw.length && !kw.some(k => desc.includes(k))) { countNoKw++; continue; }
  out.push({
    runId: ctx.runId,
    ingestUrl: ctx.ingestUrl,
    ingestSecret: ctx.ingestSecret,
    cpeClasses: c.cpeClasses || [],
    id: String(a.id),
    price: a.price,
    surface: a.propertySurface,
    commune: (a.geo && a.geo.cityName) || '',
    rooms: a.bedroomsCount,
    title: (a.title || '').toString(),
    url: 'https://www.athome.lu' + (permById[a.id] || ('/vente/appartement/luxembourg/id-' + a.id + '.html')),
    _stats: { total, pageCount: list.length, countSold, countNew, countNoKw },
  });
}

if (out.length === 0) {
  return [{ json: { _empty: true, runId: ctx.runId, ingestUrl: ctx.ingestUrl, ingestSecret: ctx.ingestSecret, _stats: { total, pageCount: list.length, countSold, countNew, countNoKw } } }];
}
return out.map(json => ({ json }));

if ($json._empty) return $json;
const meta = $('Parse + filtre liste').item.json;
const html = $json.data || $json.body || '';
const norm = html.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ');
const m = norm.match(/Classe\s+[\u00e9e]nerg[\u00e9e]?tique[^A-Za-z]{0,40}?([A-I])\b/i);
const cpe = m ? m[1].toUpperCase() : null;
const classes = meta.cpeClasses || [];
const keep = !classes.length || (cpe && classes.includes(cpe));
return { ...meta, cpe, _keep: keep };

const all = $input.all().map(i => i.json);
const first = $('Construit URL SRP').first().json;
const kept = all.filter(x => x._keep);
const listings = kept.map(({ runId, ingestUrl, ingestSecret, cpeClasses, _keep, _empty, _stats, ...rest }) => rest);
return [{ json: { ingestUrl: first.ingestUrl, runId: first.runId, ingestSecret: first.ingestSecret, listings } }];
